"use client";

import { useState, useEffect, useCallback } from 'react';
import { type Bill } from '@/types';

const STORAGE_KEY = 'offline-bill-boss-bills';

export function useBills() {
  const [bills, setBills] = useState<Bill[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    try {
      const items = window.localStorage.getItem(STORAGE_KEY);
      if (items) {
        setBills(JSON.parse(items));
      }
    } catch (error) {
      console.error("Failed to load bills from local storage", error);
    } finally {
      setLoading(false);
    }
  }, []);

  const saveBills = useCallback((newBills: Bill[]) => {
    try {
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(newBills));
      setBills(newBills);
    } catch (error) {
      console.error("Failed to save bills to local storage", error);
    }
  }, []);

  const addBill = (bill: Omit<Bill, 'id'>) => {
    const newBill: Bill = { ...bill, id: new Date().toISOString() };
    const updatedBills = [...bills, newBill];
    saveBills(updatedBills);
  };

  const updateBill = (updatedBill: Bill) => {
    const updatedBills = bills.map((bill) =>
      bill.id === updatedBill.id ? updatedBill : bill
    );
    saveBills(updatedBills);
  };

  const deleteBill = (id: string) => {
    const updatedBills = bills.filter((bill) => bill.id !== id);
    saveBills(updatedBills);
  };
  
  const getBill = (id: string) => {
    return bills.find((bill) => bill.id === id);
  };

  return { bills, loading, addBill, updateBill, deleteBill, getBill };
}
