"use client";

import { type Bill } from "@/types";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { MoreVertical, Edit, Trash2, Bell, AtSign } from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { format, parseISO, isPast, isToday } from "date-fns";

interface BillCardProps {
  bill: Bill;
  onEdit: () => void;
  onDelete: () => void;
  onStatusChange: (isPaid: boolean) => void;
  onReminderChange: (type: 'localReminder' | 'emailReminder', value: boolean) => void;
}

export default function BillCard({ bill, onEdit, onDelete, onStatusChange, onReminderChange }: BillCardProps) {
  const { toast } = useToast();
  const dueDate = parseISO(bill.dueDate);
  const isOverdue = isPast(dueDate) && !isToday(dueDate) && !bill.isPaid;

  const handleLocalReminderChange = async (checked: boolean) => {
    if(checked && Notification.permission !== 'granted') {
        const permission = await Notification.requestPermission();
        if (permission !== 'granted') {
            toast({
                variant: 'destructive',
                title: 'Permission Denied',
                description: 'Local notifications cannot be enabled without permission.'
            });
            return;
        }
    }
    onReminderChange('localReminder', checked);
    toast({
        title: 'Reminder updated',
        description: `Local reminders are now ${checked ? 'ON' : 'OFF'}.`
    });
  }

  const handleEmailReminderChange = (checked: boolean) => {
    onReminderChange('emailReminder', checked);
    toast({
        title: 'Reminder updated',
        description: `Email reminders are now ${checked ? 'ON' : 'OFF'}.`
    });
  }

  return (
    <Card className={cn("flex flex-col", { "border-destructive/50": isOverdue, "bg-muted/30": bill.isPaid })}>
      <CardHeader className="flex flex-row items-start justify-between pb-2">
        <div className="space-y-1">
          <CardTitle className="text-lg">{bill.name}</CardTitle>
          <CardDescription>Due: {format(dueDate, 'PPP')}</CardDescription>
        </div>
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <MoreVertical className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={onEdit}><Edit className="mr-2 h-4 w-4"/>Edit</DropdownMenuItem>
            <AlertDialog>
                <AlertDialogTrigger asChild>
                    <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                        <Trash2 className="mr-2 h-4 w-4"/>Delete
                    </DropdownMenuItem>
                </AlertDialogTrigger>
                <AlertDialogContent>
                    <AlertDialogHeader>
                    <AlertDialogTitle>Are you sure?</AlertDialogTitle>
                    <AlertDialogDescription>
                        This action cannot be undone. This will permanently delete this bill.
                    </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction onClick={onDelete} className="bg-destructive hover:bg-destructive/90">Delete</AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
          </DropdownMenuContent>
        </DropdownMenu>
      </CardHeader>
      <CardContent className="flex-grow space-y-4">
        <div className="text-4xl font-bold">${bill.amount.toFixed(2)}</div>
        <div>
          {bill.isPaid ? (
            <Badge variant="secondary" className="bg-green-200 text-green-800 dark:bg-green-800 dark:text-green-200">Paid</Badge>
          ) : isOverdue ? (
            <Badge variant="destructive">Overdue</Badge>
          ) : (
            <Badge variant="outline">Unpaid</Badge>
          )}
        </div>
        <div className="space-y-3 pt-2">
            <div className="flex items-center space-x-2">
                <Checkbox id={`local-${bill.id}`} checked={bill.localReminder} onCheckedChange={(c) => handleLocalReminderChange(c as boolean)} />
                <Label htmlFor={`local-${bill.id}`} className="flex items-center gap-2 text-sm font-normal text-muted-foreground"><Bell className="h-4 w-4"/>Local Reminder</Label>
            </div>
            <div className="flex items-center space-x-2">
                <Checkbox id={`email-${bill.id}`} checked={bill.emailReminder} onCheckedChange={(c) => handleEmailReminderChange(c as boolean)} />
                <Label htmlFor={`email-${bill.id}`} className="flex items-center gap-2 text-sm font-normal text-muted-foreground"><AtSign className="h-4 w-4"/>Email Reminder</Label>
            </div>
        </div>
      </CardContent>
      <CardFooter>
        <div className="flex items-center space-x-2 w-full">
            <Checkbox id={`paid-${bill.id}`} checked={bill.isPaid} onCheckedChange={(c) => onStatusChange(c as boolean)} />
            <Label htmlFor={`paid-${bill.id}`} className="font-semibold">{bill.isPaid ? 'Mark as Unpaid' : 'Mark as Paid'}</Label>
        </div>
      </CardFooter>
    </Card>
  );
}
